# --- plot helpers (hidden) — two pinnable curves: Lock and Unlock ---
# 'Lock' plots the student's OWN encrypt(m). 'Unlock' plots decrypt(encrypt(m)),
# which should land back on the diagonal. Each falls back to built-in pow until
# the student's functions work, so the panel is never blank.
def __diag(n):
    return [[m, m] for m in range(n)]

def __plot_lock(e, n):
    try:
        locked = [[m, encrypt(m, e, n)] for m in range(n)]                 # <- the STUDENT's function
        if locked and all(isinstance(pt[1], int) for pt in locked):
            return [
                {"name": "after locking with public key (your code)", "points": locked, "highlight": True},
                {"name": "no lock (m \u2192 m)", "points": __diag(n), "highlight": False},
            ]
    except Exception:
        pass
    locked = [[m, pow(m, e, n)] for m in range(n)]
    return [
        {"name": "after locking with public key", "points": locked, "highlight": True},
        {"name": "no lock (m \u2192 m)", "points": __diag(n), "highlight": False},
    ]

def __plot_unlock(e, d, n):
    try:
        unlocked = [[m, decrypt(encrypt(m, e, n), d, n)] for m in range(n)]  # <- the STUDENT's functions
        locked = [[m, encrypt(m, e, n)] for m in range(n)]
        if unlocked and all(isinstance(pt[1], int) for pt in unlocked):
            return [
                {"name": "unlocked with private key (back home, your code)", "points": unlocked, "highlight": True},
                {"name": "after locking with public key", "points": locked, "highlight": False},
            ]
    except Exception:
        pass
    locked = [[m, pow(m, e, n)] for m in range(n)]
    unlocked = [[m, pow(pow(m, e, n), d, n)] for m in range(n)]
    return [
        {"name": "unlocked with private key (back home)", "points": unlocked, "highlight": True},
        {"name": "after locking with public key", "points": locked, "highlight": False},
    ]
